import{_ as d,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"隨機圖片 API 與訪客圖庫","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/random-image-api-and-public-gallery.md","filePath":"zh-TW/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"zh-TW/Other/random-image-api-and-public-gallery.md"};function s(i,t,c,p,n,l){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="隨機圖片-api-與訪客圖庫" tabindex="-1">隨機圖片 API 與訪客圖庫 <a class="header-anchor" href="#隨機圖片-api-與訪客圖庫" aria-label="Permalink to &quot;隨機圖片 API 與訪客圖庫&quot;">​</a></h1><p>這兩個功能都在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定</span></span></code></pre></div><h2 id="隨機圖片-api" tabindex="-1">隨機圖片 API <a class="header-anchor" href="#隨機圖片-api" aria-label="Permalink to &quot;隨機圖片 API&quot;">​</a></h2><p>隨機圖片 API 會從指定目錄中隨機取出一個檔案，適合做網站背景、頭像輪播或外部頁面的隨機圖片呼叫。</p><p>啟用後可以訪問：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/random</span></span></code></pre></div><h2 id="隨機圖片-api-設定" tabindex="-1">隨機圖片 API 設定 <a class="header-anchor" href="#隨機圖片-api-設定" aria-label="Permalink to &quot;隨機圖片 API 設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>作用</th></tr></thead><tbody><tr><td>啟用</td><td>開啟或關閉 <code>/random</code>，關閉時會拒絕訪問</td></tr><tr><td>目錄</td><td>限制隨機 API 可從哪些目錄取檔案</td></tr><tr><td>呼叫示範</td><td>產生可直接複製的隨機圖 API 連結</td></tr></tbody></table><p>目錄可以選多個。例如只允許 <code>/landscape/</code> 和 <code>/portrait/</code>，隨機 API 就只能從這兩個目錄或其子目錄取檔。</p><h2 id="api-參數" tabindex="-1">API 參數 <a class="header-anchor" href="#api-參數" aria-label="Permalink to &quot;API 參數&quot;">​</a></h2><table tabindex="0"><thead><tr><th>參數</th><th>範例</th><th>作用</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>指定隨機目錄</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>指定媒體類型，可用 <code>image</code>、<code>video</code>、<code>audio</code>，也可逗號組合</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>圖片方向篩選，可用 <code>portrait</code>、<code>landscape</code>、<code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>回傳格式。空白為跳轉，<code>url</code> 回傳純連結，<code>json</code> 回傳 JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>搭配 <code>type=url</code> 使用，回傳完整連結</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>年齡分級篩選</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>只隨機包含這些標籤的檔案</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>排除包含這些標籤的檔案</td></tr></tbody></table><h2 id="回傳格式" tabindex="-1">回傳格式 <a class="header-anchor" href="#回傳格式" aria-label="Permalink to &quot;回傳格式&quot;">​</a></h2><p>不帶 <code>type</code> 時，會直接跳轉到隨機檔案位址。</p><p><code>type=url</code> 回傳文字連結。</p><p><code>type=json</code> 回傳檔案資訊，包含連結、檔案 ID、檔名、檔案類型、標籤、分級等。</p><h2 id="存取限制" tabindex="-1">存取限制 <a class="header-anchor" href="#存取限制" aria-label="Permalink to &quot;存取限制&quot;">​</a></h2><p>隨機圖片 API 會遵守後台公開訪問規則：</p><table tabindex="0"><thead><tr><th>規則</th><th>效果</th></tr></thead><tbody><tr><td>目錄限制</td><td>只能隨機允許目錄裡的檔案</td></tr><tr><td>黑名單</td><td>黑名單檔案不會進入候選池</td></tr><tr><td>白名單模式</td><td>開啟後只會回傳允許公開訪問的檔案</td></tr><tr><td>年齡分級</td><td>依目前存取模式過濾 R12、R16、R18 等內容</td></tr></tbody></table><p>如果篩選後沒有可用檔案，會回傳沒有符合結果。</p><h2 id="快取說明" tabindex="-1">快取說明 <a class="header-anchor" href="#快取說明" aria-label="Permalink to &quot;快取說明&quot;">​</a></h2><p>隨機圖片 API 會快取目錄候選池，提高訪問速度。</p><p>檔案變更後，系統會更新目錄快取版本，後續請求會重新產生候選池。空目錄也會短時間快取，避免反覆查詢。</p><h2 id="訪客圖庫" tabindex="-1">訪客圖庫 <a class="header-anchor" href="#訪客圖庫" aria-label="Permalink to &quot;訪客圖庫&quot;">​</a></h2><p>訪客圖庫提供只讀公開瀏覽頁，讓訪客查看你允許公開的目錄。</p><p>啟用後可以訪問：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/browse/目錄名</span></span></code></pre></div><h2 id="訪客圖庫設定" tabindex="-1">訪客圖庫設定 <a class="header-anchor" href="#訪客圖庫設定" aria-label="Permalink to &quot;訪客圖庫設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>作用</th></tr></thead><tbody><tr><td>啟用</td><td>開啟或關閉訪客圖庫</td></tr><tr><td>圖片載入模式</td><td>控制預覽使用原圖或縮圖</td></tr><tr><td>開放目錄</td><td>設定訪客可以訪問哪些目錄</td></tr></tbody></table><h2 id="開放目錄" tabindex="-1">開放目錄 <a class="header-anchor" href="#開放目錄" aria-label="Permalink to &quot;開放目錄&quot;">​</a></h2><p>例如填：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>訪客就可以訪問：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/browse/1</span></span>
<span class="line"><span>https://你的網域/browse/2</span></span>
<span class="line"><span>https://你的網域/browse/landscape</span></span>
<span class="line"><span>https://你的網域/browse/portrait</span></span></code></pre></div><p>也可以開放子目錄，例如 <code>/2026/lucky/</code>。訪客訪問未開放目錄會被拒絕。</p><h2 id="訪客圖庫能做什麼" tabindex="-1">訪客圖庫能做什麼 <a class="header-anchor" href="#訪客圖庫能做什麼" aria-label="Permalink to &quot;訪客圖庫能做什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td>瀏覽目錄</td><td>查看開放目錄裡的檔案和子目錄</td></tr><tr><td>搜尋</td><td>依檔名、檔案 ID、標籤搜尋</td></tr><tr><td>類型篩選</td><td>篩選圖片、影片、音訊或其他檔案</td></tr><tr><td>標籤篩選</td><td>包含指定標籤或排除指定標籤</td></tr><tr><td>方向篩選</td><td>篩選橫圖或直圖</td></tr><tr><td>時間篩選</td><td>依上傳時間範圍篩選</td></tr><tr><td>副檔名篩選</td><td>依副檔名篩選</td></tr><tr><td>複製連結</td><td>複製檔案訪問連結</td></tr><tr><td>媒體預覽</td><td>圖片、影片、音訊可在訪客頁查看或播放</td></tr></tbody></table><h2 id="訪客圖庫訪問規則" tabindex="-1">訪客圖庫訪問規則 <a class="header-anchor" href="#訪客圖庫訪問規則" aria-label="Permalink to &quot;訪客圖庫訪問規則&quot;">​</a></h2><table tabindex="0"><thead><tr><th>規則</th><th>效果</th></tr></thead><tbody><tr><td>開放目錄</td><td>只顯示允許開放的目錄</td></tr><tr><td>存取模式</td><td>依目前年齡分級存取模式過濾</td></tr><tr><td>白名單模式</td><td>開啟後只顯示允許公開訪問的檔案</td></tr><tr><td>黑名單</td><td>黑名單檔案不會顯示</td></tr></tbody></table>`,39)])])}const u=d(r,[["render",s]]);export{b as __pageData,u as default};
